  const { cart } = useCart()
  const price = calculateCartWithProgressiveDiscount(data.categories, cart, data.progressiveDiscount)
  console.log(price)
  return (
    <div className="p-4 bg-foreground absolute bottom-0 w-full flex flex-col box-shadow">
      <div className="flex flex-row justify-between">
        <span className="text-sm font-bold">Progressive Discount</span>
        <span className="text- font-semibold underline text-sm text-lightText">Learn more</span>
      </div>
      { data.progressiveDiscount && (
       <div className="pb-6 pt-4">

         <ProgressiveDiscountBar
           progressiveDiscount={data.progressiveDiscount}
         />
       </div>
      )}
      <div className="flex flex-row items-center justify-between">
        <div className="flex flex-row">
          <div className="flex flex-col">
            <span className="text-sm font-semibold line-through">{formatCurrency(price.fullPrice)}</span>
            <span className="text-[22px] font-bold">{formatCurrency(price.discountedPrice)}</span>
          </div>
        </div>
        <div>
          <Button className="py-3 px-8 bg-brandBackground text-[16px]">
            My Cart
          </Button>
        </div>
      </div>
    </div>
  )
