import TCart from "@/types/cart";
import TCategory from "../../src/types/category";
import TProgressiveDiscount, { TProgressiveDiscountStep } from "../../src/types/progressiveDiscount";
import TProduct from "../../src/types/product";

type TResult = {
  fullPrice: number;
  discountedPrice: number;
  discountAmount: number;
  appliedStep: TProgressiveDiscountStep | null;
};

export function calculateCartWithProgressiveDiscount(
  categories: TCategory[],
  cart: TCart,
  progressiveDiscount: TProgressiveDiscount | null
): TResult {
  const productMap = new Map<string, TProduct>();

  for (const category of categories) {
    for (const product of category.products) {
      productMap.set(product.id, product);
    }
  }

  let fullPrice = 0;

  for (const item of cart.items) {
    const product = productMap.get(item.productId);

    if (!product || typeof product.price !== "number") continue;

    fullPrice += product.price;
  }

  fullPrice = Number(fullPrice.toFixed(2));

  if (!progressiveDiscount || !progressiveDiscount.steps.length) {
    return {
      fullPrice,
      discountedPrice: fullPrice,
      discountAmount: 0,
      appliedStep: null,
    };
  }

  const appliedStep =
    progressiveDiscount.steps
      .filter(
        (step) =>
          typeof step.amount === "number" && fullPrice >= step.amount && step.type === 'PERCENTAGEDISCOUNT'
      )
      .sort((a, b) => (b.amount ?? 0) - (a.amount ?? 0))[0] ?? null;

  let discountedPrice = fullPrice;

  if (
    appliedStep?.type === "PERCENTAGEDISCOUNT" &&
    typeof appliedStep.discount === "number"
  ) {
    discountedPrice = fullPrice * (1 - appliedStep.discount / 100);
  }

  discountedPrice = Math.max(0, Number(discountedPrice.toFixed(2)));

  return {
    fullPrice,
    discountedPrice,
    discountAmount: Number((fullPrice - discountedPrice).toFixed(2)),
    appliedStep,
  };
}
