import { Dialog, DialogClose, DialogContent } from "@/components/ui/dialog"
import TProduct from "../../../src/types/product"
import formatCurrency from "@/utils/formatCurrecy"
import Button from "./Button"
import { useCart } from "./CartContext"
import { FiArrowLeft } from 'react-icons/fi'

type TProductModal = {
  product: TProduct | null
  onClose: () => void
}

const ProductModal: React.FC<TProductModal> = ({
  product,
  onClose
}) => {
  const { addItem } = useCart()

  return (
    <Dialog open={product !== null} onOpenChange={onClose}>
      <DialogContent showCloseButton={false} className="w-full h-full p-0 bg-foreground">
        {product && (
          <div>
            <div>
              <DialogClose className="absolute top-4 left-4 p-3 rounded-full bg-background"><FiArrowLeft size={18} /></DialogClose>
              {product.photos && product.photos[0] && <img src={product.photos[0]?.url} alt={`${product.name} photo`} className="h-100 object-cover" />}
            </div>
            <div className="pt-6 px-4">
              <span className="text-2xl font-bold">{product.name}</span>
              <div className="flex flex-row gap-2 text-[20px]">
                {product.price && <span className="font-extrabold">{formatCurrency(product.price)}</span>}
                {product.comparedAtPrice && <span className="font-semibold line-through">{formatCurrency(product.comparedAtPrice)}</span>}
              </div>
            </div>
            <div className="absolute bottom-0 py-5 px-4 bg-background w-full">
              <Button onClick={() => addItem({
                productId: product.id
              })} className="text-[16px] font-bold bg-brandBackground py-3 px-8">Add</Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  )
}

export default ProductModal
